INSERT INTO role_permission (role_id, module_name, action_name, permission_code, display_name, allow_flag, created_at, created_by)
SELECT r.id, src.module_name, src.action_name, src.permission_code, src.display_name, 1, NOW(), 'RBAC_HARDENING'
FROM roles r
JOIN (
    SELECT 'SYSTEM_ADMIN' AS role_code, 'TRANSACTIONS' AS module_name, 'DEPOSIT' AS action_name, 'TRANSACTION_DEPOSIT' AS permission_code, 'Transactions - Post Cash Deposit' AS display_name
    UNION ALL SELECT 'SYSTEM_ADMIN','TRANSACTIONS','WITHDRAW','TRANSACTION_WITHDRAW','Transactions - Post Cash Withdrawal'
    UNION ALL SELECT 'SYSTEM_ADMIN','TRANSACTIONS','TRANSFER','TRANSACTION_TRANSFER','Transactions - Post Fund Transfer'
    UNION ALL SELECT 'SYSTEM_ADMIN','TRANSACTIONS','CHEQUE_CLEARING','TRANSACTION_CHEQUE_CLEARING','Transactions - Post Cheque Clearing'
    UNION ALL SELECT 'SYSTEM_ADMIN','TRANSACTIONS','STANDING_INSTRUCTION_CREATE','TRANSACTION_STANDING_INSTRUCTION_CREATE','Transactions - Create Standing Instruction'
    UNION ALL SELECT 'SYSTEM_ADMIN','TRANSACTIONS','REVERSE','TRANSACTION_REVERSE','Transactions - Reverse Transaction'
    UNION ALL SELECT 'SYSTEM_ADMIN','FINANCING','VERIFY','FINANCING_VERIFY','Financing - Verify Financing Application'
    UNION ALL SELECT 'SYSTEM_ADMIN','FINANCING','REVIEW','FINANCING_REVIEW','Financing - Send for Shariah Review'
    UNION ALL SELECT 'SYSTEM_ADMIN','FINANCING','APPROVE','FINANCING_APPROVE','Financing - Approve Financing Application'
    UNION ALL SELECT 'SYSTEM_ADMIN','FINANCING','REJECT','FINANCING_REJECT','Financing - Reject Financing Application'
    UNION ALL SELECT 'SYSTEM_ADMIN','FINANCING','RETURN','FINANCING_RETURN','Financing - Return Financing Application'
    UNION ALL SELECT 'SYSTEM_ADMIN','FINANCING','DISBURSE','FINANCING_DISBURSE','Financing - Disburse Financing'
    UNION ALL SELECT 'SYSTEM_ADMIN','FINANCING','COLLECT_PAYMENT','FINANCING_COLLECT_PAYMENT','Financing - Collect Financing Repayment'
    UNION ALL SELECT 'SYSTEM_ADMIN','CONTRACTS','GENERATE','CONTRACT_GENERATE','Contracts - Generate Contract'
    UNION ALL SELECT 'SYSTEM_ADMIN','CONTRACTS','CUSTOMER_SIGN','CONTRACT_CUSTOMER_SIGN','Contracts - Capture Customer Signature'
    UNION ALL SELECT 'SYSTEM_ADMIN','CONTRACTS','SHARIAH_SIGN','CONTRACT_SHARIAH_SIGN','Contracts - Capture Shariah Signature'
    UNION ALL SELECT 'SYSTEM_ADMIN','SHARIAH_REVIEW','CHECKLIST_SAVE','SHARIAH_CHECKLIST_SAVE','Shariah Review - Save Shariah Checklist'
    UNION ALL SELECT 'SYSTEM_ADMIN','SHARIAH_REVIEW','APPROVE','SHARIAH_APPROVE','Shariah Review - Approve Shariah Review'
    UNION ALL SELECT 'SYSTEM_ADMIN','SHARIAH_REVIEW','REJECT','SHARIAH_REJECT','Shariah Review - Reject Shariah Review'
    UNION ALL SELECT 'SYSTEM_ADMIN','SHARIAH_REVIEW','RETURN','SHARIAH_RETURN','Shariah Review - Return Shariah Review'
    UNION ALL SELECT 'SYSTEM_ADMIN','ZAKAT_CHARITY','CALCULATE','ZAKAT_CALCULATE','Zakat & Charity - Run Zakat Calculation'
    UNION ALL SELECT 'SYSTEM_ADMIN','ZAKAT_CHARITY','PAYOUT_CREATE','CHARITY_PAYOUT_CREATE','Zakat & Charity - Create Charity Payout'
    UNION ALL SELECT 'TELLER','TRANSACTIONS','DEPOSIT','TRANSACTION_DEPOSIT','Transactions - Post Cash Deposit'
    UNION ALL SELECT 'TELLER','TRANSACTIONS','WITHDRAW','TRANSACTION_WITHDRAW','Transactions - Post Cash Withdrawal'
    UNION ALL SELECT 'TELLER','TRANSACTIONS','TRANSFER','TRANSACTION_TRANSFER','Transactions - Post Fund Transfer'
    UNION ALL SELECT 'TELLER','TRANSACTIONS','CHEQUE_CLEARING','TRANSACTION_CHEQUE_CLEARING','Transactions - Post Cheque Clearing'
    UNION ALL SELECT 'TELLER','TRANSACTIONS','STANDING_INSTRUCTION_CREATE','TRANSACTION_STANDING_INSTRUCTION_CREATE','Transactions - Create Standing Instruction'
    UNION ALL SELECT 'OPERATIONS_OFFICER','TRANSACTIONS','DEPOSIT','TRANSACTION_DEPOSIT','Transactions - Post Cash Deposit'
    UNION ALL SELECT 'OPERATIONS_OFFICER','TRANSACTIONS','WITHDRAW','TRANSACTION_WITHDRAW','Transactions - Post Cash Withdrawal'
    UNION ALL SELECT 'OPERATIONS_OFFICER','TRANSACTIONS','TRANSFER','TRANSACTION_TRANSFER','Transactions - Post Fund Transfer'
    UNION ALL SELECT 'OPERATIONS_OFFICER','TRANSACTIONS','CHEQUE_CLEARING','TRANSACTION_CHEQUE_CLEARING','Transactions - Post Cheque Clearing'
    UNION ALL SELECT 'OPERATIONS_OFFICER','TRANSACTIONS','STANDING_INSTRUCTION_CREATE','TRANSACTION_STANDING_INSTRUCTION_CREATE','Transactions - Create Standing Instruction'
    UNION ALL SELECT 'OPERATIONS_OFFICER','ZAKAT_CHARITY','CALCULATE','ZAKAT_CALCULATE','Zakat & Charity - Run Zakat Calculation'
    UNION ALL SELECT 'OPERATIONS_OFFICER','ZAKAT_CHARITY','PAYOUT_CREATE','CHARITY_PAYOUT_CREATE','Zakat & Charity - Create Charity Payout'
    UNION ALL SELECT 'INVESTMENT_OFFICER','FINANCING','VERIFY','FINANCING_VERIFY','Financing - Verify Financing Application'
    UNION ALL SELECT 'INVESTMENT_OFFICER','FINANCING','REVIEW','FINANCING_REVIEW','Financing - Send for Shariah Review'
    UNION ALL SELECT 'INVESTMENT_OFFICER','FINANCING','APPROVE','FINANCING_APPROVE','Financing - Approve Financing Application'
    UNION ALL SELECT 'INVESTMENT_OFFICER','FINANCING','REJECT','FINANCING_REJECT','Financing - Reject Financing Application'
    UNION ALL SELECT 'INVESTMENT_OFFICER','FINANCING','RETURN','FINANCING_RETURN','Financing - Return Financing Application'
    UNION ALL SELECT 'INVESTMENT_OFFICER','FINANCING','COLLECT_PAYMENT','FINANCING_COLLECT_PAYMENT','Financing - Collect Financing Repayment'
    UNION ALL SELECT 'INVESTMENT_OFFICER','CONTRACTS','GENERATE','CONTRACT_GENERATE','Contracts - Generate Contract'
    UNION ALL SELECT 'INVESTMENT_OFFICER','CONTRACTS','CUSTOMER_SIGN','CONTRACT_CUSTOMER_SIGN','Contracts - Capture Customer Signature'
    UNION ALL SELECT 'BRANCH_MANAGER','FINANCING','ACCESS','FINANCING_ACCESS','Financing - Module Access'
    UNION ALL SELECT 'BRANCH_MANAGER','FINANCING','DISBURSE','FINANCING_DISBURSE','Financing - Disburse Financing'
    UNION ALL SELECT 'SHARIAH_BOARD_MEMBER','SHARIAH_REVIEW','CHECKLIST_SAVE','SHARIAH_CHECKLIST_SAVE','Shariah Review - Save Shariah Checklist'
    UNION ALL SELECT 'SHARIAH_BOARD_MEMBER','SHARIAH_REVIEW','APPROVE','SHARIAH_APPROVE','Shariah Review - Approve Shariah Review'
    UNION ALL SELECT 'SHARIAH_BOARD_MEMBER','SHARIAH_REVIEW','REJECT','SHARIAH_REJECT','Shariah Review - Reject Shariah Review'
    UNION ALL SELECT 'SHARIAH_BOARD_MEMBER','SHARIAH_REVIEW','RETURN','SHARIAH_RETURN','Shariah Review - Return Shariah Review'
    UNION ALL SELECT 'SHARIAH_BOARD_MEMBER','CONTRACTS','SHARIAH_SIGN','CONTRACT_SHARIAH_SIGN','Contracts - Capture Shariah Signature'
    UNION ALL SELECT 'CUSTOMER','CONTRACTS','ACCESS','CONTRACTS_ACCESS','Contracts - Module Access'
    UNION ALL SELECT 'CUSTOMER','CONTRACTS','CUSTOMER_SIGN','CONTRACT_CUSTOMER_SIGN','Contracts - Capture Customer Signature'
) src ON src.role_code = r.code
LEFT JOIN role_permission rp
    ON rp.role_id = r.id
   AND rp.permission_code = src.permission_code
WHERE rp.id IS NULL;
